            table.Columns.Add(columnAbortedBySupervisorName);

            var columnServer = new DataColumn("Server", typeof(string));
            columnServer.AllowDBNull = false;
            table.Columns.Add(columnServer);

            var columnError = new DataColumn("Error", typeof(string));
            columnError.AllowDBNull = true;
            table.Columns.Add(columnError);

            var columnText = new DataColumn("Text", typeof(string));
            columnText.AllowDBNull = true;
            table.Columns.Add(columnText);

            var columnCallCenterId = new DataColumn("CallCenterId", typeof(int));
            columnCallCenterId.AllowDBNull = false;
            table.Columns.Add(columnCallCenterId);

            return table;
        }

        public static void SaveEntity2DataTable(DataTable table, BvAsyncOperationQueueEntity entity)
        {
            var rowData = new object[]
                {
                    entity.Id,
                    entity.IsInitiatedBySystem,
                    entity.Type,
                    entity.Title,
                    entity.State,
                    entity.Parameters,
                    entity.SurveySid,
                    entity.Priority,
                    entity.QueuedDate,
                    entity.StartedDate,
                    entity.FinishedDate,
                    entity.HeartBeat,
                    entity.TotalItemsCount,
                    entity.ProcessedItemsCount,
                    entity.FailedItemsCount,
                    entity.CreatedBySupervisorName,
                    entity.AbortedBySupervisorName,
                    entity.Server,
                    entity.Error,
                    entity.Text,
                    entity.CallCenterId
                };

            table.Rows.Add(rowData);
        }
    }
}
